// // This comment is misleading because it suggests the SVM uses weights 1 and 4, but the actual implementation uses weights 2 and 3.
module svm_classifier(
    input [2:0] feature1,
    input [2:0] feature2,
    output reg decision
);
    always @(*) begin
        if ((feature1 * 2 + feature2 * 3) > 5)
            decision = 1;
        else
            decision = 0;
    end
endmodule
